// Package collab implements multi-agent document collaboration state management.
// State is stored in .entire/collab/<collab-id>/state.json with file-level locking
// for atomic claim/handoff operations.
package collab

import (
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"syscall"
	"time"

	"github.com/entireio/cli/cmd/entire/cli/paths"
)

// Status values for a collaboration.
const (
	StatusActive       = "active"
	StatusPaused       = "paused"
	StatusImplementing = "implementing"
	StatusCompleted    = "completed"
)

// Mode values for a collaboration.
const (
	ModeOrchestrated = "orchestrated"
	ModeDualSession  = "dual-session"
)

// ImplStatus values for agent implementation status.
const (
	ImplStatusPending = "pending"
	ImplStatusWorking = "working"
	ImplStatusDone    = "done"
)

// State represents the full state of a collaboration session.
// Stored at .entire/collab/<collab-id>/state.json
type State struct {
	CollabID     string      `json:"collab_id"`
	DocumentPath string      `json:"document_path"`
	Status       string      `json:"status"`
	Mode         string      `json:"mode"`
	Turn         TurnState   `json:"turn"`
	Agents       []Agent     `json:"agents"`
	Config       Config      `json:"config"`
	History      []TurnEntry `json:"history"`

	// Implementation fields (present when status is "implementing")
	BaseBranch string `json:"base_branch,omitempty"`
	BaseCommit string `json:"base_commit,omitempty"`
}

// TurnState tracks the current turn.
type TurnState struct {
	Number       int    `json:"number"`
	Agent        string `json:"agent"`
	Version      int    `json:"version"`
	StartedAt    string `json:"started_at"`
	LeaseSeconds int    `json:"lease_seconds"`
}

// Agent represents a registered agent in the collaboration.
type Agent struct {
	Type           string `json:"type"`
	SessionID      string `json:"session_id,omitempty"`
	Role           string `json:"role,omitempty"`
	TurnsCompleted int    `json:"turns_completed"`

	// Implementation fields
	Branch     string `json:"branch,omitempty"`
	Worktree   string `json:"worktree,omitempty"`
	ImplStatus string `json:"impl_status,omitempty"`
}

// Config holds collaboration configuration.
type Config struct {
	MaxTurns  *int     `json:"max_turns"`
	TurnOrder []string `json:"turn_order"`
}

// TurnEntry records a completed turn in the history.
type TurnEntry struct {
	Turn      int    `json:"turn"`
	Agent     string `json:"agent"`
	Snapshot  string `json:"snapshot,omitempty"`
	Summary   string `json:"summary,omitempty"`
	Timestamp string `json:"timestamp"`
	Expired   bool   `json:"expired,omitempty"`
}

// IsLeaseExpired returns true if the current turn's lease has expired.
func (s *State) IsLeaseExpired() bool {
	t, err := time.Parse(time.RFC3339, s.Turn.StartedAt)
	if err != nil {
		return false
	}
	return time.Since(t) > time.Duration(s.Turn.LeaseSeconds)*time.Second
}

// NextAgent returns the next agent in the turn order after the given agent.
func (s *State) NextAgent(currentAgent string) string {
	order := s.Config.TurnOrder
	for i, a := range order {
		if a == currentAgent {
			return order[(i+1)%len(order)]
		}
	}
	if len(order) > 0 {
		return order[0]
	}
	return ""
}

// NonExpiredHistoryCount returns the count of history entries that are not expired.
func (s *State) NonExpiredHistoryCount() int {
	count := 0
	for _, h := range s.History {
		if !h.Expired {
			count++
		}
	}
	return count
}

// GenerateCollabID creates a random 8-character hex ID.
func GenerateCollabID() (string, error) {
	b := make([]byte, 4)
	if _, err := rand.Read(b); err != nil {
		return "", fmt.Errorf("generating collab ID: %w", err)
	}
	return hex.EncodeToString(b), nil
}

// Store manages collab state files on disk.
type Store struct {
	baseDir string // .entire/collab/
}

// NewStore creates a Store for the current git worktree.
func NewStore() (*Store, error) {
	root, err := paths.WorktreeRoot(nil)
	if err != nil {
		return nil, fmt.Errorf("not a git repository: %w", err)
	}
	return &Store{baseDir: filepath.Join(root, ".entire", "collab")}, nil
}

// CollabDir returns the directory for a specific collaboration.
func (s *Store) CollabDir(collabID string) string {
	return filepath.Join(s.baseDir, collabID)
}

// SnapshotsDir returns the snapshots directory for a collaboration.
func (s *Store) SnapshotsDir(collabID string) string {
	return filepath.Join(s.baseDir, collabID, "snapshots")
}

// ContextPath returns the context.md path for a collaboration.
func (s *Store) ContextPath(collabID string) string {
	return filepath.Join(s.baseDir, collabID, "context.md")
}

// StatePath returns the state.json path for a collaboration.
func (s *Store) StatePath(collabID string) string {
	return filepath.Join(s.baseDir, collabID, "state.json")
}

// LockPath returns the lock file path for a collaboration.
func (s *Store) LockPath(collabID string) string {
	return filepath.Join(s.baseDir, collabID, "state.lock")
}

// Init creates the directory structure for a new collaboration.
func (s *Store) Init(collabID string) error {
	if err := os.MkdirAll(s.SnapshotsDir(collabID), 0o750); err != nil {
		return fmt.Errorf("creating collab directories: %w", err)
	}
	return nil
}

// Save writes state to disk atomically (write tmp + rename).
func (s *Store) Save(state *State) error {
	dir := s.CollabDir(state.CollabID)
	if err := os.MkdirAll(dir, 0o750); err != nil {
		return fmt.Errorf("creating collab directory: %w", err)
	}

	data, err := json.MarshalIndent(state, "", "  ")
	if err != nil {
		return fmt.Errorf("marshaling state: %w", err)
	}
	data = append(data, '\n')

	statePath := s.StatePath(state.CollabID)
	tmpPath := statePath + ".tmp"

	if err := os.WriteFile(tmpPath, data, 0o600); err != nil {
		return fmt.Errorf("writing temp state: %w", err)
	}
	if err := os.Rename(tmpPath, statePath); err != nil {
		return fmt.Errorf("renaming state file: %w", err)
	}
	return nil
}

// Load reads a collaboration state from disk.
func (s *Store) Load(collabID string) (*State, error) {
	data, err := os.ReadFile(s.StatePath(collabID))
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil //nolint:nilnil // not found is not an error
		}
		return nil, fmt.Errorf("reading state: %w", err)
	}

	var state State
	if err := json.Unmarshal(data, &state); err != nil {
		return nil, fmt.Errorf("unmarshaling state: %w", err)
	}
	return &state, nil
}

// List returns all collab IDs that have state.json files.
func (s *Store) List() ([]string, error) {
	entries, err := os.ReadDir(s.baseDir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, fmt.Errorf("reading collab directory: %w", err)
	}

	var ids []string
	for _, e := range entries {
		if !e.IsDir() {
			continue
		}
		statePath := filepath.Join(s.baseDir, e.Name(), "state.json")
		if _, err := os.Stat(statePath); err == nil {
			ids = append(ids, e.Name())
		}
	}
	return ids, nil
}

// FindByDocument finds the active collaboration for a given document path.
func (s *Store) FindByDocument(docPath string) (*State, error) {
	ids, err := s.List()
	if err != nil {
		return nil, err
	}

	for _, id := range ids {
		state, err := s.Load(id)
		if err != nil || state == nil {
			continue
		}
		if state.DocumentPath == docPath && (state.Status == StatusActive || state.Status == StatusPaused || state.Status == StatusImplementing) {
			return state, nil
		}
	}
	return nil, nil //nolint:nilnil // not found is not an error
}

// WithLock executes fn while holding an exclusive file lock on the collaboration.
// This ensures atomic claim/handoff operations.
func (s *Store) WithLock(collabID string, fn func() error) error {
	lockPath := s.LockPath(collabID)

	// Ensure directory exists
	if err := os.MkdirAll(filepath.Dir(lockPath), 0o750); err != nil {
		return fmt.Errorf("creating lock directory: %w", err)
	}

	f, err := os.OpenFile(lockPath, os.O_CREATE|os.O_WRONLY, 0o600)
	if err != nil {
		return fmt.Errorf("opening lock file: %w", err)
	}
	defer f.Close()

	if err := syscall.Flock(int(f.Fd()), syscall.LOCK_EX); err != nil {
		return fmt.Errorf("acquiring lock: %w", err)
	}
	defer syscall.Flock(int(f.Fd()), syscall.LOCK_UN) //nolint:errcheck // best-effort unlock

	return fn()
}

// ClaimTurn atomically claims the current turn for the given agent.
// Returns the updated state, or an error if the claim fails.
func (s *Store) ClaimTurn(collabID string, agentType string) (*State, error) {
	var result *State

	err := s.WithLock(collabID, func() error {
		state, err := s.Load(collabID)
		if err != nil {
			return fmt.Errorf("loading state: %w", err)
		}
		if state == nil {
			return fmt.Errorf("collaboration %s not found", collabID)
		}

		if state.Status != StatusActive {
			return fmt.Errorf("collaboration is %s, not active", state.Status)
		}

		// Verify it's this agent's turn or the lease is expired
		isMyTurn := state.Turn.Agent == agentType
		leaseExpired := state.IsLeaseExpired()

		if !isMyTurn && !leaseExpired {
			return fmt.Errorf("not your turn (current: %s, lease expires in %ds)",
				state.Turn.Agent,
				state.Turn.LeaseSeconds-int(time.Since(mustParseTime(state.Turn.StartedAt)).Seconds()))
		}

		// If reclaiming an expired turn, record the expiry
		if !isMyTurn && leaseExpired {
			state.History = append(state.History, TurnEntry{
				Turn:      state.Turn.Number,
				Agent:     state.Turn.Agent,
				Timestamp: time.Now().UTC().Format(time.RFC3339),
				Expired:   true,
			})
		}

		// Claim the turn
		state.Turn.Agent = agentType
		state.Turn.StartedAt = time.Now().UTC().Format(time.RFC3339)
		state.Turn.Version++

		if err := s.Save(state); err != nil {
			return fmt.Errorf("saving state: %w", err)
		}

		result = state
		return nil
	})

	return result, err
}

// Handoff atomically completes the current turn: writes snapshot, updates state.
// Returns the updated state, or an error if the handoff fails.
func (s *Store) Handoff(collabID string, agentType string, expectedVersion int, summary string) (*State, error) {
	var result *State

	err := s.WithLock(collabID, func() error {
		state, err := s.Load(collabID)
		if err != nil {
			return fmt.Errorf("loading state: %w", err)
		}
		if state == nil {
			return fmt.Errorf("collaboration %s not found", collabID)
		}

		// Verify fencing token
		if state.Turn.Version != expectedVersion {
			return fmt.Errorf("version mismatch (expected %d, got %d) — turn was reclaimed",
				expectedVersion, state.Turn.Version)
		}

		// Copy document to snapshot
		docExt := filepath.Ext(state.DocumentPath)
		if docExt == "" {
			docExt = ".md"
		}
		snapshotName := fmt.Sprintf("turn-%d%s", state.Turn.Number, docExt)
		snapshotPath := filepath.Join(s.SnapshotsDir(collabID), snapshotName)

		docData, err := os.ReadFile(state.DocumentPath)
		if err != nil {
			return fmt.Errorf("reading document for snapshot: %w", err)
		}
		if err := os.WriteFile(snapshotPath, docData, 0o600); err != nil {
			return fmt.Errorf("writing snapshot: %w", err)
		}

		// Update history
		state.History = append(state.History, TurnEntry{
			Turn:      state.Turn.Number,
			Agent:     agentType,
			Snapshot:  fmt.Sprintf("snapshots/%s", snapshotName),
			Summary:   summary,
			Timestamp: time.Now().UTC().Format(time.RFC3339),
		})

		// Update agent's turns completed
		for i := range state.Agents {
			if state.Agents[i].Type == agentType {
				state.Agents[i].TurnsCompleted++
				break
			}
		}

		// Advance to next turn
		state.Turn.Agent = state.NextAgent(agentType)
		state.Turn.Number++
		state.Turn.Version++
		state.Turn.StartedAt = time.Now().UTC().Format(time.RFC3339)

		// Check termination
		if state.Config.MaxTurns != nil && state.Turn.Number > *state.Config.MaxTurns {
			state.Status = StatusCompleted
			// Clean up snapshots
			_ = os.RemoveAll(s.SnapshotsDir(collabID)) //nolint:errcheck // best-effort
		}

		if err := s.Save(state); err != nil {
			return fmt.Errorf("saving state: %w", err)
		}

		result = state
		return nil
	})

	return result, err
}

// Delete removes all files for a collaboration.
func (s *Store) Delete(collabID string) error {
	dir := s.CollabDir(collabID)
	if err := os.RemoveAll(dir); err != nil {
		return fmt.Errorf("removing collab directory: %w", err)
	}
	return nil
}

// SnapshotDiff returns the diff between the previous turn's snapshot and the current document.
// Returns empty string if no previous snapshot exists.
func (s *Store) SnapshotDiff(collabID string, turnNumber int, documentPath string) (string, error) {
	if turnNumber <= 1 {
		return "", nil
	}

	// Find the previous non-expired turn's snapshot
	state, err := s.Load(collabID)
	if err != nil || state == nil {
		return "", err
	}

	var prevSnapshot string
	for i := len(state.History) - 1; i >= 0; i-- {
		h := state.History[i]
		if !h.Expired && h.Snapshot != "" {
			prevSnapshot = filepath.Join(s.CollabDir(collabID), h.Snapshot)
			break
		}
	}

	if prevSnapshot == "" {
		return "", nil
	}

	if _, err := os.Stat(prevSnapshot); os.IsNotExist(err) {
		return "", nil // Snapshot missing (partial crash), gracefully skip
	}

	// Read both files and compute a simple diff
	oldData, err := os.ReadFile(prevSnapshot)
	if err != nil {
		return "", fmt.Errorf("reading snapshot: %w", err)
	}
	newData, err := os.ReadFile(documentPath)
	if err != nil {
		return "", fmt.Errorf("reading document: %w", err)
	}

	if string(oldData) == string(newData) {
		return "(no changes)", nil
	}

	// Return a simple line-based diff summary
	oldLines := strings.Split(string(oldData), "\n")
	newLines := strings.Split(string(newData), "\n")
	return fmt.Sprintf("-%d lines, +%d lines (was %d, now %d)",
		len(oldLines), len(newLines), len(oldLines), len(newLines)), nil
}

func mustParseTime(s string) time.Time {
	t, err := time.Parse(time.RFC3339, s)
	if err != nil {
		return time.Time{}
	}
	return t
}

