// ClaimTurn atomically claims the current turn for the given agent.
//
// In dual-session mode: any agent can claim if no one else is actively editing
// (the turn.agent field is empty or the lease has expired). No turn-order enforcement.
//
// In orchestrator mode: enforces turn order — only the assigned agent can claim.
//
// Returns the updated state, or an error if the claim fails.
func (s *Store) ClaimTurn(collabID string, agentType string) (*State, error) {
	var result *State

	err := s.WithLock(collabID, func() error {
		state, err := s.Load(collabID)
		if err != nil {
			return fmt.Errorf("loading state: %w", err)
		}
		if state == nil {
			return fmt.Errorf("collaboration %s not found", collabID)
		}

		if state.Status != StatusActive {
			return fmt.Errorf("collaboration is %s, not active", state.Status)
		}

		someoneElseEditing := state.Turn.Agent != "" && state.Turn.Agent != agentType
		leaseExpired := state.IsLeaseExpired()

		if state.Mode == ModeOrchestrated {
			// Orchestrator mode: enforce turn order
			isMyTurn := state.Turn.Agent == agentType
			if !isMyTurn && !leaseExpired {
				return fmt.Errorf("not your turn (current: %s, lease expires in %ds)",
					state.Turn.Agent,
					state.Turn.LeaseSeconds-int(time.Since(mustParseTime(state.Turn.StartedAt)).Seconds()))
			}
		} else {
			// Dual-session mode: anyone can claim if no one is editing
			if someoneElseEditing && !leaseExpired {
				return fmt.Errorf("%s is currently editing (started %s ago, lease %ds)",
					state.Turn.Agent,
					time.Since(mustParseTime(state.Turn.StartedAt)).Truncate(time.Second),
					state.Turn.LeaseSeconds)
			}
		}

		// If reclaiming from another agent (expired lease), record the expiry
		if someoneElseEditing && leaseExpired {
			state.History = append(state.History, TurnEntry{
				Turn:      state.Turn.Number,
				Agent:     state.Turn.Agent,
				Timestamp: time.Now().UTC().Format(time.RFC3339),
				Expired:   true,
			})
		}

		// Claim
		state.Turn.Agent = agentType
		state.Turn.StartedAt = time.Now().UTC().Format(time.RFC3339)
		state.Turn.Version++

		if err := s.Save(state); err != nil {
			return fmt.Errorf("saving state: %w", err)
		}

		result = state
		return nil
	})

	return result, err
}

