package cli

import (
	"context"
	"fmt"
	"log/slog"
	"os"
	"strings"

	"github.com/entireio/cli/cmd/entire/cli/collab"
	"github.com/entireio/cli/cmd/entire/cli/logging"
)

// handleCollabOnTurnEnd checks for active collaborations and auto-handoffs
// if the collab document was modified during this turn. Called from
// handleLifecycleTurnEnd after SaveStep completes.
func handleCollabOnTurnEnd(ctx context.Context, agentType string, modifiedFiles []string) {
	logCtx := logging.WithComponent(ctx, "collab")

	store, err := collab.NewStore(ctx)
	if err != nil {
		return // Not a git repo or collab not supported — silently skip
	}

	collabIDs, err := store.List()
	if err != nil || len(collabIDs) == 0 {
		return // No collabs exist — nothing to do
	}

	for _, id := range collabIDs {
		state, err := store.Load(id)
		if err != nil || state == nil {
			continue
		}

		if state.Status != collab.StatusActive {
			continue
		}

		if state.DocumentPath == "" {
			continue
		}

		// Check if the collab document was modified in this turn
		if !fileInList(state.DocumentPath, modifiedFiles) {
			continue
		}

		// Generate a summary from the diff
		summary := generateDiffSummary(store, state)

		// Auto-handoff: snapshot + update state
		// Use the current turn version — since this is hook-driven,
		// no explicit claim happened, so we pass the current version.
		_, handoffErr := store.Handoff(id, agentType, state.Turn.Version, summary)
		if handoffErr != nil {
			logging.Warn(logCtx, "collab auto-handoff failed",
				slog.String("collab_id", id),
				slog.String("error", handoffErr.Error()))
			continue
		}

		logging.Info(logCtx, "collab auto-handoff",
			slog.String("collab_id", id),
			slog.String("agent", agentType),
			slog.String("summary", summary))
	}
}

// generateDiffSummary creates a brief summary by diffing the document
// against the last snapshot.
func generateDiffSummary(store *collab.Store, state *collab.State) string {
	diff, err := store.SnapshotDiff(state.CollabID, state.Turn.Number, state.DocumentPath)
	if err != nil || diff == "" {
		// Fall back to reading the document and reporting its size
		data, readErr := os.ReadFile(state.DocumentPath)
		if readErr != nil {
			return "modified document"
		}
		lines := strings.Count(string(data), "\n") + 1
		return fmt.Sprintf("modified document (%d lines)", lines)
	}
	return diff
}

// fileInList checks if a file path is in the list of modified files.
// Handles both exact matches and suffix matches (for relative vs absolute paths).
func fileInList(target string, files []string) bool {
	for _, f := range files {
		if f == target {
			return true
		}
		if strings.HasSuffix(f, "/"+target) || strings.HasSuffix(target, "/"+f) {
			return true
		}
	}
	return false
}

